import anthropic
import json

client = anthropic.Anthropic()

# --- Sub-agents (specialized workers) ---

def search_agent(query: str) -> str:
    """Sub-agent: search for factual information and return a summary."""
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=256,
        system="You are a search agent. Answer the query with factual, concise information.",
        messages=[{"role": "user", "content": query}],
    )
    return resp.content[0].text

def math_agent(expression: str) -> str:
    """Sub-agent: evaluate a mathematical expression or word problem."""
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=128,
        system="You are a math agent. Compute the answer and return only the numeric result with one sentence of explanation.",
        messages=[{"role": "user", "content": expression}],
    )
    return resp.content[0].text

def writer_agent(instructions: str) -> str:
    """Sub-agent: draft text based on instructions and collected facts."""
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        system="You are a writing agent. Produce polished prose based on the instructions given.",
        messages=[{"role": "user", "content": instructions}],
    )
    return resp.content[0].text

# --- Sub-agent dispatch table ---
SUB_AGENTS = {
    "search_agent": search_agent,
    "math_agent": math_agent,
    "writer_agent": writer_agent,
}

# --- Orchestrator tool definitions ---
ORCHESTRATOR_TOOLS = [
    {
        "name": "search_agent",
        "description": "Search for factual information on any topic. Use for research sub-goals.",
        "input_schema": {
            "type": "object",
            "properties": {"query": {"type": "string", "description": "The research question"}},
            "required": ["query"],
        },
    },
    {
        "name": "math_agent",
        "description": "Evaluate mathematical expressions or word problems.",
        "input_schema": {
            "type": "object",
            "properties": {"expression": {"type": "string", "description": "The expression or problem to solve"}},
            "required": ["expression"],
        },
    },
    {
        "name": "writer_agent",
        "description": "Draft final text from instructions and gathered facts.",
        "input_schema": {
            "type": "object",
            "properties": {"instructions": {"type": "string", "description": "Writing instructions with context"}},
            "required": ["instructions"],
        },
    },
]

def run_orchestrator(goal: str, max_rounds: int = 6) -> str:
    """
    Orchestrator loop: call sub-agents as tools until the goal is achieved.
    Returns the final synthesized answer.
    """
    messages = [{"role": "user", "content": goal}]

    for _ in range(max_rounds):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=1024,
            system=(
                "You are an orchestrator. Break the user's goal into sub-goals and delegate each to the "
                "appropriate sub-agent. Collect their results and synthesize a final answer."
            ),
            tools=ORCHESTRATOR_TOOLS,
            messages=messages,
        )

        # Collect any text from this turn
        final_text = ""
        tool_calls = []
        for block in resp.content:
            if block.type == "text":
                final_text = block.text
            elif block.type == "tool_use":
                tool_calls.append(block)

        if resp.stop_reason == "end_turn":
            return final_text

        if not tool_calls:
            return final_text

        # Append orchestrator's response to messages
        messages.append({"role": "assistant", "content": resp.content})

        # Execute each sub-agent call and collect results
        tool_results = []
        for tc in tool_calls:
            fn = SUB_AGENTS.get(tc.name)
            if fn is None:
                result = json.dumps({"error": f"Unknown sub-agent: {tc.name}"})
            else:
                result = fn(**tc.input)
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": tc.id,
                "content": result,
            })

        messages.append({"role": "user", "content": tool_results})

    return "Orchestrator reached max rounds without completing."

# Example usage:
goal = (
    "Research the population of Tokyo and the population of New York City. "
    "Compute the ratio of Tokyo's population to NYC's population. "
    "Write a one-paragraph comparison of the two cities' population sizes."
)
answer = run_orchestrator(goal)
print(answer)
